@async_time_it
async def get_script(
    topic_plan: List[dict],
    director_plan: List[dict],
    max_retries=3
) -> str:
    """并发预处理所有Topic的RAG参考资料"""
    logger.info("正在并发获取所有 Topic 的参考资料...")

    async def fetch_rag_for_topic(topic):
        return await raw_text_rag(topic['zero_to_hero_logic'])
    
    # 打包所有 RAG 任务并并发发射
    rag_tasks = [fetch_rag_for_topic(topic) for topic in topic_plan]
    all_rag_results = await asyncio.gather(*rag_tasks)
    
    logger.info("所有参考资料准备完毕，开始Topic级别并发生成对话...")

    """并发生成每个Topic的对话脚本"""
    max_concurrent_topics = 10
    semaphore = asyncio.Semaphore(max_concurrent_topics)

    async def process_single_topic_script(idx, topic, stages, rag_query_results):
        async with semaphore:
            last_ai_message_content = "这是上一轮AI的发言内容，当前是第一轮，所以没有。"
            topic_script = ""
            counter = 0  # 每次重置意味着新课题永远由 A (奇数) 先开口

            logger.info(f"🚀 开始生成课题 [{topic['topic_name']}] 的脚本...")

            for stage_idx, stage in enumerate(stages):
                for bullet_idx, bullet in enumerate(stage['bullets']):
                    counter += 1

                    # 组装任务信息(使用 .get() 防御大模型幻觉)
                    current_task = CurrentTask(
                        topic_id=idx + 1,
                        stage_id=stage_idx + 1,
                        bullet_id=bullet_idx + 1,
                        intent=bullet.get('intent', ''),
                        guidance=bullet.get('guidance', ''),
                        transition_hint=bullet.get('transition_hint', ''),
                        topic_zero_to_hero_logic=topic['zero_to_hero_logic'],
                        stage_plan=stages,
                        rag_query_results=rag_query_results
                    )

                    # 奇数轮：A（纳西妲）
                    if counter % 2 == 1:
                        task_prompt = TASK_PROMPT_NAHIDA.invoke({
                            "intent": current_task['intent'],
                            "guidance": current_task['guidance'],
                            "transition_hint": current_task['transition_hint'],
                            "topic_zero_to_hero_logic": current_task['topic_zero_to_hero_logic'],
                            "stage_plan": current_task['stage_plan'],
                            "rag_query_results": current_task['rag_query_results'],
                            "last_ai_message_content": last_ai_message_content
                        })
                        nahida_response = await llm.ainvoke(task_prompt)
                        topic_script += f"\nA：{nahida_response.content}\n"
                        last_ai_message_content = nahida_response.content

                    # 偶数轮：B（艾尔海森）
                    else:
                        task_prompt = TASK_PROMPT_HAISEN.invoke({
                            "intent": current_task['intent'],
                            "guidance": current_task['guidance'],
                            "transition_hint": current_task['transition_hint'],
                            "topic_zero_to_hero_logic": current_task['topic_zero_to_hero_logic'],
                            "stage_plan": current_task['stage_plan'],
                            "rag_query_results": current_task['rag_query_results'],
                            "last_ai_message_content": last_ai_message_content
                        })
                        haisen_response = await llm.ainvoke(task_prompt)
                        topic_script += f"\nB：{haisen_response.content}\n"
                        last_ai_message_content = haisen_response.content
                        
            logger.info(f"✅ 课题 [{topic['topic_name']}] 脚本生成完毕！")
            return topic_script
    
    # 打包所有 Topic 的 script 生成任务并发执行
    script_tasks = [
        process_single_topic_script(idx, topic, director_plan[idx]['stages'], all_rag_results[idx])
        for idx, topic in enumerate(topic_plan)
    ]

    topic_scripts_results = await asyncio.gather(*script_tasks)
    final_script = "".join(topic_scripts_results)
    
    script_local_path = str(RESOURCES_DIR / "documents" / "static" / f"podcast_script_{uuid4()}.txt")
    with open(script_local_path, "w", encoding="utf-8") as f:
        f.write(final_script)

    return final_script


@async_time_it
async def agent_speechers_node(state: VideoState) -> Command:
    """对话播客阶段，输入stage_plan和rag_query_results，输出script"""
    topic_plan = state['topic_plan']
    director_plan = state['director_plan']
    script = await get_script(topic_plan, director_plan)
    return Command(
        update={
            "messages": [AIMessage(content=f"配音阶段完成，生成的script如下：{script}")],
            "step": "agent_speechers",
            "timings": {"agent_speechers_node": 1.0},

            "script": script
        },
        goto="polish"
    )

